# Shapes module: Abstract base and concrete implementations
from types import Color, IMeasurable, Point, Bounds

# Abstract base class for all shapes
@abstract
class Shape(IMeasurable):
    center: Point
    _color: Color

    def __init__(self, center: Point, color: Color):
        self.center = center
        self._color = color

    @virtual
    def get_color(self) -> Color:
        return self._color

    @final
    def position_str(self) -> str:
        return f"({self.center.x}, {self.center.y})"

    @abstract
    def draw(self) -> str

    @abstract
    def get_bounds(self) -> Bounds

    def color_name(self) -> str:
        c: Color = self.get_color()
        if c == Color.RED:
            return "red"
        elif c == Color.GREEN:
            return "green"
        elif c == Color.BLUE:
            return "blue"
        elif c == Color.BLACK:
            return "black"
        elif c == Color.WHITE:
            return "white"
        else:
            return "unknown"

class Circle(Shape):
    radius: float

    def __init__(self, center: Point, radius: float, color: Color):
        super().__init__(center, color)
        self.radius = radius

    @override
    def draw(self) -> str:
        c: str = self.color_name()
        return f"Circle({c}, r={self.radius})"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def get_bounds(self) -> Bounds:
        r: float = self.radius
        min_p: Point = Point(self.center.x - r, self.center.y - r)
        max_p: Point = Point(self.center.x + r, self.center.y + r)
        return Bounds(min_p, max_p)

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, center: Point, width: float, height: float, color: Color):
        super().__init__(center, color)
        self.width = width
        self.height = height

    @override
    def draw(self) -> str:
        c: str = self.color_name()
        w: int = int(self.width)
        h: int = int(self.height)
        return f"Rectangle({c}, {w}x{h})"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def get_bounds(self) -> Bounds:
        w2: float = self.width / 2.0
        h2: float = self.height / 2.0
        min_p: Point = Point(self.center.x - w2, self.center.y - h2)
        max_p: Point = Point(self.center.x + w2, self.center.y + h2)
        return Bounds(min_p, max_p)

class Triangle(Shape):
    base: float
    tri_height: float

    def __init__(self, center: Point, base: float, height: float, color: Color):
        super().__init__(center, color)
        self.base = base
        self.tri_height = height

    @override
    def draw(self) -> str:
        c: str = self.color_name()
        return f"Triangle({c}, b={self.base}, h={self.tri_height})"

    @override
    def area(self) -> float:
        return 0.5 * self.base * self.tri_height

    @override
    def get_bounds(self) -> Bounds:
        w2: float = self.base / 2.0
        h2: float = self.tri_height / 2.0
        min_p: Point = Point(self.center.x - w2, self.center.y - h2)
        max_p: Point = Point(self.center.x + w2, self.center.y + h2)
        return Bounds(min_p, max_p)

