# Utils module: Generic utilities and helper functions
from types import Point, Color, IMeasurable
from shapes import Shape, Rectangle, Triangle

# Static utility class for geometry operations
class GeometryUtils:
    @static
    def distance_squared(p1: Point, p2: Point) -> float:
        dx: float = p1.x - p2.x
        dy: float = p1.y - p2.y
        return dx * dx + dy * dy

    @static
    def origin() -> Point:
        return Point(0.0, 0.0)

    @static
    def color_brightness(c: Color) -> str:
        v: int = c.value
        return "bright" if v > 0x800000 else "dark"

# Generic container class with constraint
class ShapeContainer[T: IMeasurable]:
    _shapes: list[T]
    _limit: int

    def __init__(self, limit: int):
        self._shapes = []
        self._limit = limit

    def add(self, shape: T) -> bool:
        if len(self._shapes) < self._limit:
            self._shapes.append(shape)
            return True
        return False

    def total_area(self) -> float:
        total: float = 0.0
        for s in self._shapes:
            total += s.area()
        return total

    def get_shapes(self) -> list[T]:
        return self._shapes

    def count(self) -> int:
        return len(self._shapes)
